  illaoi: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Dodge her E with your E \u2014 fight away from tentacles.", breakdown: "Her E on a dash is dodgeable. Use E to dodge her E, fight in the open, and Q3-W her.", dos: ["E-dodge her E", "Fight away from tentacles", "Q3-W her in the open"], donts: ["Get E\u2019d in tentacle range", "Fight in her field", "Get spirit-slammed"], key: { slot: "E", name: "Test of Spirit", cd: "16s", note: "Her vessel pull. Dodge with E.", winT: "TEST OF SPIRIT DOWN", winS: "Q3-R her." }, hold: "Hold E to dodge her E \u2014 spirit-dash sideways as she casts, then return and Q3-W her in the open.", tip: "Use your E to dodge her E spirit-test \u2014 then fight her away from her tentacles where she\u2019s weak.", win: "Dodge her E and fight in the open." },
